Парсит **OpenAPI/Swagger-спеку** (JSON или YAML) и автоматически дёргает каждый `path` x `method`, помечая аномалии: **200 на эндпоинте, который должен требовать auth** (broken access control), и **500** (необработанная ошибка - точка для дальнейшего фаззинга). Path-параметры подставляются плейсхолдером.

> Спека = карта атаки. Прогоняй дважды: без токена и с токеном low-priv. Эндпоинт, отдающий 200 без токена или одинаковый ответ обоим ролям, - кандидат на BOLA/BFLA.

deps: `pip install requests pyyaml`. placeholders: `{{SPEC}}` (URL или файл openapi.json), `{{BASE}}` (база API), `{{TOKEN}}` опц.

```python
#!/usr/bin/env python3
# openapi_mass_test.py - ARS3NAL (GPL-3.0). Only for AUTHORIZED testing.
import argparse, json, sys, requests
try:
    import yaml
except ImportError:
    yaml = None

def load_spec(src):
    if src.startswith("http"):
        txt = requests.get(src, verify=False, timeout=20).text
    else:
        txt = open(src, encoding="utf-8").read()
    try:
        return json.loads(txt)
    except json.JSONDecodeError:
        if not yaml:
            sys.exit("[!] YAML spec but pyyaml missing: pip install pyyaml")
        return yaml.safe_load(txt)

def base_url(spec, override):
    if override:
        return override.rstrip("/")
    servers = spec.get("servers") or []
    if servers:
        return servers[0]["url"].rstrip("/")
    # swagger 2.0
    host = spec.get("host", "")
    bp = spec.get("basePath", "")
    sch = (spec.get("schemes") or ["https"])[0]
    return f"{sch}://{host}{bp}".rstrip("/")

def fill_path(p):
    # /users/{id} -> /users/1 ; {uuid} -> placeholder
    import re
    return re.sub(r"\{[^}]+\}", "1", p)

def main():
    ap = argparse.ArgumentParser(description="ARS3NAL OpenAPI mass tester")
    ap.add_argument("-s", "--spec", required=True, help="openapi.json/.yaml URL or file")
    ap.add_argument("-b", "--base", default="", help="override base URL")
    ap.add_argument("-t", "--token", default="", help="bearer token (run once with, once without)")
    ap.add_argument("--timeout", type=int, default=15)
    a = ap.parse_args()
    requests.packages.urllib3.disable_warnings()
    spec = load_spec(a.spec)
    base = base_url(spec, a.base)
    hdr = {"Authorization": "Bearer " + a.token} if a.token else {}
    print(f"[*] base={base}  auth={'yes' if a.token else 'NONE'}\n")
    paths = spec.get("paths", {})
    for path, ops in paths.items():
        for method, meta in ops.items():
            m = method.upper()
            if m not in ("GET", "POST", "PUT", "DELETE", "PATCH"):
                continue
            url = base + fill_path(path)
            secured = bool(meta.get("security") or spec.get("security"))
            try:
                r = requests.request(m, url, headers=hdr, timeout=a.timeout,
                                     verify=False, allow_redirects=False)
                code = r.status_code
            except requests.RequestException as e:
                print(f"  ERR  {m:6s} {path}  ({e})"); continue
            flag = ""
            if secured and not a.token and code == 200:
                flag = "  <-- 200 on SECURED w/o token (BAC?)"
            elif code == 500:
                flag = "  <-- 500 server error (fuzz target)"
            elif code in (401, 403):
                flag = ""
            print(f"  {code}  {m:6s} {path}{flag}")
    print("\n[=] сравни этот прогон с прогоном под другой ролью (BOLA/BFLA)")

if __name__ == "__main__":
    main()
```

Запуск:
```bash
python3 openapi_mass_test.py -s https://target/openapi.json            # без токена
python3 openapi_mass_test.py -s ./swagger.yaml -b https://target/api -t "$TOKEN"
```
